<?php namespace App\Repositories\Admission;use App\Repositories\BaseRepository;use App\Models\Admission\EntranceExam;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class EntranceExamRepository extends BaseRepository{    public function __construct(EntranceExam $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getUpcomingExams(): Collection    {        return $this->query()->where('exam_date', '>=', now())->where('status', 'scheduled')->get();    }    public function getPastExams(): Collection    {        return $this->query()->where('exam_date', '<', now())->get();    }    public function findByAcademicYear(int $academicYearId): Collection    {        return $this->findByField('academic_year_id', $academicYearId);    }    public function findByClass(int $classId): Collection    {        return $this->findByField('class_id', $classId);    }    public function searchExams(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('exam_date', [$startDate, $endDate])->get();    }}